function processData(input) {
  // Get the response
  const response = input.content || 'No response received';
  const category = input.category || 'Category not determined';

  // Get current date for the ticket
  const currentDate = new Date();
  const ticketId = 'TKT-' + Math.floor(Math.random() * 10000) + '-' + currentDate.getFullYear();

  // Format the response
  const formattedResponse = `
    Customer Service Response
    ------------------------
    Ticket ID: ${ticketId}
    Category: ${category}
    Date: ${currentDate.toLocaleDateString()}

    ${response}

    If you have any further questions, please don't hesitate to contact us.
    Customer Service Team
  `;

  return {
    formattedResponse,
    category,
    ticketId,
    timestamp: currentDate.toISOString(),
    metadata: {
      responseTime: new Date().getTime() - currentDate.getTime(),
      department: getDepartmentFromCategory(category)
    }
  };
}

// Helper function to determine department
function getDepartmentFromCategory(category) {
  if (category.toLowerCase().includes('technical') || category.toLowerCase().includes('tech')) {
    return 'Technical Support';
  } else if (category.toLowerCase().includes('order') || category.toLowerCase().includes('status')) {
    return 'Order Management';
  } else if (category.toLowerCase().includes('return') || category.toLowerCase().includes('refund')) {
    return 'Returns Department';
  } else {
    return 'General Customer Service';
  }
}

function processData(input) {
  // Simply return the input as the final output
  return input;
}
